  { name: "Python", level: 90 },
  { name: "Java", level: 60 },
  { name: "JavaScript / React", level: 80 },
  { name: "Machine Learning", level: 75 },
  { name: "Web Development", level: 85 },
  { name: "Linux & Networks", level: 70 }
];

const softSkills = [
  "Problem-solving",
  "Teamwork & Collaboration",
  "Project Management",
  "Communication",
  "Adaptability",
  "Analytical mindset",
];

const Skills = () => {
    return(
        <div className="skills-container">
            <div className="hard-skills">
                <h1 className="title"> Hard skills</h1>
                {hardSkills.map((skill, index) =>
                    (<div key={index} className="skill-name">
                        <h3 className="skill-title">{skill.name}<span style={{ fontSize: "0.9rem", color: "#555" }}> ({skill.level}%)</span></h3>
                        <progress value={skill.level} max="100"></progress>
                    </div >)
                
                )}
            </div>
            <div className="soft-skills">
                <h1 className="title">Soft skills</h1>
                {softSkills.map((skill, index) => (
